SELECT ,
FROM yx_knowledge_entry e LEFT JOIN yx_knowledge_category c ON e.category_id = c.id AND c.is_deleted = FALSE LEFT JOIN yx_user u ON e.author_id = u.id AND u.is_deleted = FALSE LEFT JOIN yx_knowledge_source s ON e.source_id = s.id AND s.is_deleted = FALSE WHERE e.is_deleted = FALSE
AND e.category_id = #{categoryId}
AND e.status = #{status}
AND e.title LIKE CONCAT('%', #{title}, '%')
ORDER BY e.updated_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM yx_knowledge_entry e
WHERE e.is_deleted = FALSE

    AND e.category_id = #{categoryId}


    AND e.status = #{status}


    AND e.title LIKE CONCAT('%', #{title}, '%')

